        for &(tv, tc) in &target_val_counts {
            let dc = derived_val_counts.iter()
                .find(|(v, _)| *v == tv)
                .map(|(_, c)| *c)
                .unwrap_or(0);
            count_drag += (tc - dc).abs();
        }

        // Cohesion is primary — scaled by target_total_cells so it dominates
        // when the transformation is relationally incoherent.
        // L1 and spectral/count are secondary refinements.
